using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// Mark the class with [McpServerToolType] so WithToolsFromAssembly() discovers it.
/// Each tool method is marked with [McpServerTool] + [Description] for LLM discovery.
/// Constructor parameters are resolved from DI — here we inject HttpClient.
/// </summary>
[McpServerToolType]
public class WeatherTools(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };

    [McpServerTool(Name = "get_forecast"), Description("Get the weather forecast for a city.")]
    public async Task<string> GetForecastAsync(
        [Description("City name, e.g. \"Seattle\"")] string city,
        [Description("Number of days (1-5)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync(
            $"/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Name = "get_alerts", ReadOnly = true), Description("Get active weather alerts for a US state.")]
    public async Task<string> GetAlertsAsync(
        [Description("Two-letter US state code, e.g. \"WA\"")] string state,
        CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetAsync(
            $"/alerts?state={Uri.EscapeDataString(state)}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

